function averageLastXHours(data, hours) {
  const now = Date.now();
  const cutoff = now - hours * 60 * 60 * 1000;

  const filtered = data.filter(entry => entry.time >= cutoff);

  if (filtered.length === 0) return null;

  const sum = filtered.reduce((acc, entry) => acc + entry.hu, 0);
  return sum / filtered.length;
}

