function getLastHourEpoch(targetHour) {
  const now = new Date();
  const last = new Date(now);

  // Set to target hour
  last.setHours(targetHour, 0, 0, 0);

  // If that time is in the future, go back one day
  if (last > now) {
    last.setDate(last.getDate() - 1);
  }

  // Epoch time in milliseconds
  return last.getTime();

  // Or, if you want seconds:
  // return Math.floor(last.getTime() / 1000);
}

function averageTempsBetween(data, startTime, endTime) {
  let sum = 0;
  let count = 0;

  // Loop backward for efficiency (if data is sorted by time ascending)
  for (let i = data.length - 1; i >= 0; i--) {
    const entry = data[i];
    const t = entry.time;

    if (t >= startTime && t <= endTime) {
      sum += entry.temp;
      count++;
    } else if (t < startTime) {
      // If data is sorted chronologically, we can stop early
      break;
    }
  }

  return count > 0 ? sum / count : 0; // Return null if no valid entries
}

