function in_hours_range(on_hour, start_minus, length) {
    const now = new Date();
    const currentHour = now.getHours(); // returns 0–23
    // normalize in case x+2 goes past 24
    var x = (on_hour - start_minus) % 24;
    const end = (x + length) % 24;
    node.warn(`current hour ${currentHour}. dump start ${x}. Dump end ${end}.`)
    if (x < end) {
        // normal case (e.g. 10 to 12)
        return currentHour >= x && currentHour < end;
    } else {
        // wrap-around case (e.g. 23 to 1)
        return currentHour >= x || currentHour < end;
    }
}

